  arrL: ico('<line x1="12" y1="8" x2="4" y2="8"/><polyline points="7 4 3 8 7 12"/>'),
  arrR: ico('<line x1="4" y1="8" x2="12" y2="8"/><polyline points="9 4 13 8 9 12"/>'),
