/* ── Public API ──────────────────────────────────────────────── */

/* ── Merged registry ─────────────────────────────────────────── */
const allDemos = Object.freeze({ ...specific, ...extras1, ...extras2, ...extras3, ...extras4 })

/**
 * Check whether a term has a visual demo.
 * @param {string} termId - The slugified term ID
 * @returns {boolean}
 */
export const hasDemo = (termId) => typeof allDemos[termId] === 'function'

/**
 * Get demo HTML for a given term.
 * @param {string} termId - The slugified term ID
 * @returns {string} HTML string
 */
export const getDemoHTML = (termId) => {
  const builder = allDemos[termId]
  return typeof builder === 'function' ? builder() : ''
}

/**
 * Set up delegated click handlers for interactive demos.
 */
export const initDemoInteractions = () => {
  const handleClick = (event) => {
    const { target } = event
    const sw = target.closest('[data-demo-toggle="switch"]')
    if (sw) { sw.classList.toggle('on'); const lb = sw.nextElementSibling; if (lb && lb.tagName !== 'BUTTON') lb.textContent = sw.classList.contains('on') ? 'ON' : 'OFF'; return }
    const cb = target.closest('[data-demo-toggle="checkbox"]')
    if (cb) { cb.classList.toggle('checked'); const sp = cb.querySelector('span:last-child'); if (sp) sp.textContent = cb.classList.contains('checked') ? 'Checked' : 'Unchecked'; return }
    const rd = target.closest('[data-demo-toggle="radio"]')
    if (rd) { const g = rd.closest('[data-demo-radio-group]'); if (g) g.querySelectorAll('[data-demo-toggle="radio"]').forEach(r => r.classList.remove('selected')); rd.classList.add('selected'); return }
    const ah = target.closest('.demo-accordion-header')
    if (ah) { const item = ah.closest('.demo-accordion-item'); if (item) item.classList.toggle('open'); return }
    const dd = target.closest('[data-demo-toggle="dropdown"]')
    if (dd) { const opt = target.closest('.demo-dropdown-option'); if (opt) { const tr = dd.querySelector('.demo-dropdown-trigger'); if (tr) tr.innerHTML = `${opt.textContent} ${I.chev}`; dd.classList.remove('open'); return } const tr = target.closest('.demo-dropdown-trigger'); if (tr) dd.classList.toggle('open'); return }
    document.querySelectorAll('.demo-dropdown-mini.open').forEach(d => { if (!d.contains(target)) d.classList.remove('open') })
  }
  document.addEventListener('click', handleClick)
}
